class Solution:
    def reverseEvenLengthGroups(self, head):
        if not head:
            return head
        prev = head
        group_len = 2
        node = head.next
        while node:
            nodes = []
            cur = node
            while cur and len(nodes) < group_len:
                nodes.append(cur)
                cur = cur.next
            count = len(nodes)
            if count % 2 == 0:
                for i in range(count - 1, 0, -1):
                    nodes[i].next = nodes[i - 1]
                prev.next = nodes[-1]
                nodes[0].next = cur
                prev = nodes[0]
            elif nodes:
                prev = nodes[-1]
            node = cur
            group_len += 1
        return head

