var reverseEvenLengthGroups = function(head) {
    if (!head) return head;
    let prev = head;
    let groupLen = 2;
    let node = head.next;
    while (node) {
        const nodes = [];
        let cur = node;
        while (cur && nodes.length < groupLen) {
            nodes.push(cur);
            cur = cur.next;
        }
        const count = nodes.length;
        if (count % 2 === 0) {
            for (let i = count - 1; i > 0; i--) {
                nodes[i].next = nodes[i - 1];
            }
            prev.next = nodes[count - 1];
            nodes[0].next = cur;
            prev = nodes[0];
        } else if (count > 0) {
            prev = nodes[count - 1];
        }
        node = cur;
        groupLen += 1;
    }
    return head;
};
